mapper.update:
WITH target_movies AS ( SELECT DISTINCT t.movie_id FROM ( VALUES
(#{movieId})
) AS t(movie_id) WHERE t.movie_id IS NOT NULL ), rating_stats AS ( SELECT tm.movie_id, COUNT(r.rating)::int AS votes, AVG(r.rating)::numeric AS avg_rating FROM target_movies tm LEFT JOIN ratings r ON r.movie_id = tm.movie_id GROUP BY tm.movie_id ), blended_calc AS ( SELECT m.movie_id, m.score AS current_score, COALESCE(rs.votes, 0) AS new_votes, CASE WHEN COALESCE(rs.votes, 0) = 0 THEN ROUND(COALESCE(m.douban_score, m.score, 0)::numeric, 1) WHEN m.douban_score IS NULL THEN ROUND((COALESCE(rs.avg_rating, 0) * 2)::numeric, 1) ELSE ROUND( ((#{kWeight} * m.douban_score + COALESCE(rs.votes, 0) * COALESCE(rs.avg_rating, 0) * 2.0) / (#{kWeight} + COALESCE(rs.votes, 0)))::numeric, 1 ) END AS blended_score FROM movies m JOIN rating_stats rs ON rs.movie_id = m.movie_id ), score_calc AS ( SELECT b.movie_id, b.new_votes, CASE WHEN b.new_votes < #{forceUpdateVotesThreshold} OR b.current_score IS NULL OR ROUND(b.current_score::numeric, 1) <> b.blended_score THEN b.blended_score ELSE b.current_score END AS target_score FROM blended_calc b ) UPDATE movies m SET votes = c.new_votes, score = c.target_score FROM score_calc c WHERE m.movie_id = c.movie_id AND (m.votes IS DISTINCT FROM c.new_votes OR m.score IS DISTINCT FROM c.target_score)
